  <Tab value="OpenAI">
    ```typescript
    import OpenAI from "openai";

    const client = new OpenAI();

    const generateText = async ({ prompt, system, maxTokens, providerOptions }) => {
      const response = await client.chat.completions.create({
        model: "gpt-4o",
        max_tokens: maxTokens,
        messages: [
          ...(system ? [{ role: "system" as const, content: system }] : []),
          { role: "user" as const, content: prompt },
        ],
      });
      return {
        text: response.choices[0]?.message?.content ?? "",
        usage: response.usage
          ? {
              inputTokens: response.usage.prompt_tokens,
              outputTokens: response.usage.completion_tokens,
            }
          : undefined,
      };
    };

    const generateObject = async ({ prompt, system, schema, maxTokens, providerOptions }) => {
      const response = await client.chat.completions.create({
        model: "gpt-4o",
        max_tokens: maxTokens,
        messages: [
          ...(system ? [{ role: "system" as const, content: system }] : []),
          {
            role: "user" as const,
            content: [
              ...(providerOptions?.pdfBase64
                ? [{ type: "file" as const, file: { filename: "document.pdf", file_data: `data:application/pdf;base64,${providerOptions.pdfBase64}` } }]
                : []),
              ...((providerOptions?.attachments as Array<{
                kind: "image" | "pdf" | "text";
                name?: string;
                mimeType?: string;
                base64?: string;
                text?: string;
              }> | undefined)?.flatMap((attachment) => {
                if (attachment.kind === "pdf" && attachment.base64) {
                  return [{
                    type: "file" as const,
                    file: {
                      filename: attachment.name ?? "attachment.pdf",
                      file_data: `data:${attachment.mimeType ?? "application/pdf"};base64,${attachment.base64}`,
                    },
                  }];
                }
                if (attachment.kind === "image" && attachment.base64) {
                  return [{
                    type: "image_url" as const,
                    image_url: { url: `data:${attachment.mimeType ?? "image/jpeg"};base64,${attachment.base64}` },
                  }];
                }
                if (attachment.kind === "text" && attachment.text) {
                  return [{ type: "text" as const, text: attachment.text }];
                }
                return [];
              }) ?? []),
              ...((providerOptions?.images as Array<{ imageBase64: string; mimeType: string }> | undefined)?.map((img) => ({
                type: "image_url" as const,
                image_url: { url: `data:${img.mimeType};base64,${img.imageBase64}` },
              })) ?? []),
              { type: "text" as const, text: prompt },
            ],
          },
        ],
      });
      const text = response.choices[0]?.message?.content ?? "{}";
      return {
        object: schema.parse(JSON.parse(text)),
        usage: response.usage
          ? {
              inputTokens: response.usage.prompt_tokens,
              outputTokens: response.usage.completion_tokens,
            }
          : undefined,
      };
    };
